+    integration_level = "advanced"
+  }
+}
+
+# ==================================================
+# セキュリティ連動スケーリング出力
+# ==================================================
+
+output "security_linked_scaling" {
+  description = "セキュリティ連動スケーリング情報"
+  value = var.enable_security_linked_scaling ? {
+    lambda_function = {
+      name = aws_lambda_function.security_scaling_controller[0].function_name
+      arn  = aws_lambda_function.security_scaling_controller[0].arn
+    }
+
+    cloudwatch_rule = {
+      name = aws_cloudwatch_event_rule.security_threshold_breach[0].name
+      arn  = aws_cloudwatch_event_rule.security_threshold_breach[0].arn
+    }
+
+    scaling_policies = {
+      scale_up_policy_arn   = aws_autoscaling_policy.security_scale_up[0].arn
+      scale_down_policy_arn = aws_autoscaling_policy.security_scale_down[0].arn
+    }
+
+    policy_configuration = var.security_threshold_scaling_policy
+  } : null
+}

